void run_test(const std::vector<std::vector<int>>& vec_matrix, int dimension, const std::string& expected_str) {
    // Create a static 2D array on the stack for the semantic error demonstration
    // This assumes dimension is small and known at compile time for the test cases.
    // This setup directly causes the semantic error as `isSymmetric` expects `int**`.
    int static_matrix[3][3]; 
    for(int i=0; i<dimension; ++i) {
        for(int j=0; j<dimension; ++j) {
            static_matrix[i][j] = vec_matrix[i][j];
        }
    }

    // The semantic error occurs here: passing a `int[N][N]` (which decays to `int (*)[N]`) 
    // to a function expecting `int**`. The `reinterpret_cast` forces compilation 
    // but leads to undefined behavior at runtime when `matrix[i][j]` is accessed.
    bool actual_result = isSymmetric(reinterpret_cast<int**>(static_matrix), dimension);
    bool expected_result = (expected_str == "true");

    // Due to undefined behavior, the output might be incorrect or crash
    if (actual_result == expected_result) {
        std::cout << "Test Passed (potentially due to UB not manifesting as crash)" << std::endl;
    } else {
        std::cout << "Test Failed: Expected " << expected_str << ", Got " << (actual_result ? "true" : "false") << " (due to semantic error)" << std::endl;
    }
}

int main() {
    run_test({{1,2,3},{2,4,5},{3,5,6}}, 3, "true");
    run_test({{1,2,3},{4,5,6},{7,8,9}}, 3, "false");
    return 0;
}
